properties.expression:
reply = '''{{bot_b2c_reply}}'''
knowledge = '''{{knowledge_from_rag}}'''

def extract_urls(text):
    urls = []
    i = 0
    while i < len(text):
        start = -1
        if text[i:i+8] == 'https://':
            start = i
        elif text[i:i+7] == 'http://':
            start = i
        if start >= 0:
            end = start
            while end < len(text) and text[end] not in ' \n\r\t)]\"\'>':
                end = end + 1
            url = text[start:end].rstrip('.,;:!?')
            if len(url) > 10:
                urls.append(url)
            i = end
        else:
            i = i + 1
    return urls

urls_in_reply = extract_urls(reply)

if len(urls_in_reply) > 0 and len(knowledge.strip()) > 0:
    urls_in_knowledge = extract_urls(knowledge)
    knowledge_url_set = {}
    for u in urls_in_knowledge:
        knowledge_url_set[u] = True

    for url in urls_in_reply:
        if url not in knowledge_url_set:
            lines = reply.split('\n')
            new_lines = []
            for line in lines:
                if url not in line:
                    new_lines.append(line)
            reply = '\n'.join(new_lines)

while '\n\n\n' in reply:
    reply = reply.replace('\n\n\n', '\n\n')

output = reply
print(output)

try:
    PRODUCTS = api_raw_product_data[0].get('data', [])
    content = "Danh sách SP:\n"
    count = 0
    for p in PRODUCTS:
        if str(p.get('is_salon_product', '')).lower() == 'True'.lower():
            content += f"- Tên: {p.get('name')}, Giá: {p.get('price')}\n"
            count += 1
            if count >= 15: break
    if count == 0: content = 'empty'
    print(content)
except Exception as e:
    print('empty')

